diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..76d6588c3ec6 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -297,6 +297,9 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
                             const APInt &DemandedElts, unsigned Depth,
                             const SimplifyQuery &Q);

+static std::pair<Value *, bool>
+getDomPredecessorCondition(const Instruction *ContextI);
+
 bool llvm::isKnownNonEqual(const Value *V1, const Value *V2,
                            const SimplifyQuery &Q, unsigned Depth) {
   // We don't support looking through casts.
@@ -3017,11 +3020,24 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
     break;
   case Instruction::Or:
     // (X | (X != 0)) is non zero
+    if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
     if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
       return true;
-    // X | Y != 0 if X != 0 or Y != 0.
-    return isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
-           isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
+    // X | Y != 0 if X != Y (since X | Y == 0 implies X == Y == 0).
+    if (Q.CxtI) {
+      auto PredCond = getDomPredecessorCondition(Q.CxtI);
+      if (PredCond.first) {
+        Value *LHS, *RHS;
+        CmpPredicate Pred;
+        if (match(PredCond.first, m_c_ICmp(Pred, m_Value(LHS), m_Value(RHS)))) {
+          if (Pred == CmpInst::ICMP_NE) {
+            if ((LHS == I->getOperand(0) && RHS == I->getOperand(1)) ||
+                (LHS == I->getOperand(1) && RHS == I->getOperand(0)))
+              return true;
+          }
+        }
+      }
+    }
   case Instruction::SExt:
   case Instruction::ZExt:
     // ext X != 0 if X != 0.

